import React from 'react';
import { Paper, Typography, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Chip, Box, TablePagination } from '@mui/material';

interface Discovery {
  repository: string;
  findingType: string;
  severity: 'Low' | 'Medium' | 'High' | 'Critical';
  language: string;
  date: string;
  riskScore: number;
}

const recentDiscoveries: Discovery[] = [
  { repository: 'my-corp/backend-api', findingType: 'Hardcoded Secrets (AWS Keys)', severity: 'Critical', language: 'Python', date: '2023-10-27', riskScore: 98 },
  { repository: 'open-source/web-app', findingType: 'Insecure Direct Object Reference', severity: 'High', language: 'JavaScript', date: '2023-10-27', riskScore: 85 },
  { repository: 'dev-team/microservice-go', findingType: 'Using Component with Known Vulnerabilities', severity: 'Medium', language: 'Go', date: '2023-10-26', riskScore: 62 },
  { repository: 'legacy-project/java-monolith', findingType: 'Missing Rate Limiting', severity: 'Low', language: 'Java', date: '2023-10-26', riskScore: 35 },
  { repository: 'test-lab/docker-compose', findingType: 'Insecure Docker Configuration', severity: 'Medium', language: 'Docker', date: '2023-10-25', riskScore: 50 },
];

const getSeverityColor = (severity: Discovery['severity']) => {
  switch (severity) {
    case 'Critical': return 'error';
    case 'High': return 'warning';
    case 'Medium': return 'info';
    case 'Low': return 'success';
    default: return 'default';
  }
};

const RecentDiscoveriesTable: React.FC = () => {
  const [page, setPage] = React.useState(0);
  const [rowsPerPage, setRowsPerPage] = React.useState(5);

  const handleChangePage = (event: unknown, newPage: number) => {
    setPage(newPage);
  };

  const handleChangeRowsPerPage = (event: React.ChangeEvent<HTMLInputElement>) => {
    setRowsPerPage(parseInt(event.target.value, 10));
    setPage(0);
  };

  return (
    <Paper sx={{ p: 2, mt: 4 }}>
      <Typography variant="h6" gutterBottom>Recent Discoveries</Typography>
      <TableContainer>
        <Table size="small">
          <TableHead>
            <TableRow>
              <TableCell>Repository</TableCell>
              <TableCell>Finding Type</TableCell>
              <TableCell>Severity</TableCell>
              <TableCell>Language</TableCell>
              <TableCell>Date</TableCell>
              <TableCell>Risk Score</TableCell>
            </TableRow>
          </TableHead>
          <TableBody>
            {recentDiscoveries
              .slice(page * rowsPerPage, page * rowsPerPage + rowsPerPage)
              .map((discovery, index) => (
                <TableRow key={index}>
                  <TableCell>{discovery.repository}</TableCell>
                  <TableCell>{discovery.findingType}</TableCell>
                  <TableCell>
                    <Chip label={discovery.severity} color={getSeverityColor(discovery.severity)} size="small" />
                  </TableCell>
                  <TableCell>{discovery.language}</TableCell>
                  <TableCell>{discovery.date}</TableCell>
                  <TableCell>{discovery.riskScore}</TableCell>
                </TableRow>
              ))}
          </TableBody>
        </Table>
      </TableContainer>
      <TablePagination
        rowsPerPageOptions={[5, 10, 25]}
        component="div"
        count={recentDiscoveries.length}
        rowsPerPage={rowsPerPage}
        page={page}
        onPageChange={handleChangePage}
        onRowsPerPageChange={handleChangeRowsPerPage}
      />
      <Box sx={{ textAlign: 'right', mt: 1 }}>
        <Typography variant="caption" color="text.secondary">
          Enterprise data
        </Typography>
      </Box>
    </Paper>
  );
};

export default RecentDiscoveriesTable;
