import React, { useState, useEffect } from 'react';
import { Paper, InputBase } from '@mui/material';

interface SearchBarProps {
  onSearch: (query: string) => void; // Still keep onSearch for when Enter is pressed
  initialQuery?: string;
}

const SearchBar: React.FC<SearchBarProps> = ({ onSearch, initialQuery }) => {
  const [query, setQuery] = useState(initialQuery || '');

  useEffect(() => {
    setQuery(initialQuery || '');
  }, [initialQuery]);

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    setQuery(e.target.value);
  };

  const handleKeyPress = (e: React.KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      e.preventDefault(); // Prevent form submission if it's part of a form
      onSearch(query);
    }
  };

  return (
    <Paper
      sx={{ p: '2px 4px', display: 'flex', alignItems: 'center', flexGrow: 1 }}
    >
      <InputBase
        sx={{ ml: 1, flex: 1 }}
        placeholder="Search GitHub (e.g., 'python jwt authentication', 'org:microsoft', 'CVE-2021-44228')"
        inputProps={{ 'aria-label': 'search github' }}
        value={query}
        onChange={handleInputChange}
        onKeyPress={handleKeyPress}
      />
    </Paper>
  );
};

export default SearchBar;
