import React, { useState } from 'react';
import { Paper, Typography, Box, Button, CircularProgress, Table, TableBody, TableCell, TableContainer, TableHead, TableRow, Alert, Link } from '@mui/material';
import { getRepositoryContent, getRepoTree } from '../../services/api';
import { GitHubRepo, GitHubTreeItem } from '../../types/github';
import { Buffer } from 'buffer';

interface SecretDetectionProps {
  owner: string;
  repoName: string;
  defaultBranch: string;
}

// Expanded regex patterns for secret detection
const secretPatterns: { [key: string]: RegExp } = {
  'AWS Access Key ID': /(A3T[A-Z0-9]|AKIA|AGPA|AIDA|AROA|AIPA|ANPA|ANVA|ASIA)[A-Z0-9]{16}/g,
  'AWS Secret Access Key': /[0-9a-zA-Z\/+]{40}/g, // Often found with AKIA
  'GitHub Token': /ghp_[0-9a-zA-Z]{36}|[a-zA-Z0-9]{39}_[a-zA-Z0-9]{35}/g, // ghp_ for PATs, gho_ for OAuth
  'GitLab Token': /glpat-[0-9a-zA-Z\-\_]{20}|glsa-[0-9a-zA-Z\-\_]{20}/g,
  'Generic API Key': /[Aa][Pp][Ii]_?[Kk][Ee][Yy]\s*[:=]\s*['"]?([a-zA-Z0-9-_.]{16,})['"]?/g,
  'JWT Secret': /eyJ[A-Za-z0-9-_=]+\.[A-Za-z0-9-_=]+\.?[A-Za-z0-9-_.+/=]*|secret|private_key/g,
  'Discord Token': /[a-zA-Z0-9]{24}\.[0-9a-zA-Z]{6}\.[0-9a-zA-Z\-\_]{27}/g,
  'Telegram Bot Token': /[0-9]{9}:[0-9a-zA-Z\-\_]{35}/g,
  'Database URL': /(mysql|postgres|mongodb|redis):\/\/[^:\s]+:[^@\s]+@[\w.-]+:\d+\/[\w.-]+/g,
  'SMTP Credentials': /(smtp|mail):\/\/[^:\s]+:[^@\s]+@[\w.-]+:\d+/g,
  'OAuth Client Secret': /[a-zA-Z0-9]{32}/g, // Often 32 chars, but can vary
  'Private Key': /-----BEGIN (RSA|EC|OPENSSH|PGP) PRIVATE KEY-----|-----BEGIN (DSA|ENCRYPTED) PRIVATE KEY-----/g,
  'PEM Certificate': /-----BEGIN (CERTIFICATE|RSA PRIVATE KEY)-----/g,
};

const fileExtensionsToScan = ['.env', '.json', '.yml', '.yaml', '.xml', '.config', '.ini', '.txt', '.log', '.pem', '.key', '.crt', '.conf', '.properties', '.sh', '.bash', '.zsh', '.ps1'];
const maxFileSize = 1024 * 1024; // 1 MB limit for file content fetching

interface FoundSecret {
  file: string;
  type: string;
  snippet: string;
  url: string;
}

const SecretDetection: React.FC<SecretDetectionProps> = ({ owner, repoName, defaultBranch }) => {
  const [secrets, setSecrets] = useState<FoundSecret[]>([]);
  const [loading, setLoading] = useState(false);
  const [scanned, setScanned] = useState(false);
  const [scanError, setScanError] = useState<string | null>(null);

  const handleScan = async () => {
    setLoading(true);
    setScanned(true);
    setSecrets([]);
    setScanError(null);

    try {
      // Get the tree for the default branch
      const treeResponse = await getRepoTree(owner, repoName, defaultBranch, true);
      const filesToProcess = treeResponse.tree.filter(
        (item: GitHubTreeItem) =>
          item.type === 'blob' && // Only files
          item.size && item.size < maxFileSize && // Not too large
          fileExtensionsToScan.some(ext => item.path.toLowerCase().endsWith(ext)) // Relevant extensions
      );

      const found: FoundSecret[] = [];
      for (const file of filesToProcess) {
        try {
          // GitHub API for content returns base64 encoded string for files
          const fileContentResponse = await getRepositoryContent(owner, repoName, file.path);
          const fileContent = Buffer.from(fileContentResponse.content, 'base64').toString('utf8');

          for (const type in secretPatterns) {
            const matches = fileContent.match(secretPatterns[type]);
            if (matches) {
              matches.forEach(match => {
                found.push({
                  file: file.path,
                  type: type,
                  snippet: `...${match.substring(0, Math.min(match.length, 10))}...${match.substring(Math.max(0, match.length - 10))}`, // Masked
                  url: `https://github.com/${owner}/${repoName}/blob/${defaultBranch}/${file.path}`
                });
              });
            }
          }
        } catch (fileError: any) {
          console.warn(`Could not fetch content for ${file.path}:`, fileError.message);
          // Continue scanning other files even if one fails
        }
      }
      setSecrets(found);
    } catch (error: any) {
      setScanError(error.message || "An error occurred during secret scan.");
      console.error("Error scanning for secrets:", error);
    } finally {
      setLoading(false);
    }
  };

  return (
    <Paper sx={{ p: 2, mt: 2 }}>
      <Typography variant="h6" gutterBottom>Secret Detection</Typography>
      <Alert severity="info" sx={{ mb: 2 }}>
        This performs an **extensive scan** on various file types across the repository for potential hardcoded secrets. This is a best-effort client-side scan and should not be considered a comprehensive security audit. Large repositories or those with many files may take longer to scan or hit API rate limits.
      </Alert>
      <Button variant="contained" onClick={handleScan} disabled={loading}>
        {loading ? <CircularProgress size={24} /> : 'Scan for Secrets'}
      </Button>
      
      {scanned && !loading && (
        <Box sx={{ mt: 2 }}>
          {scanError && <Alert severity="error">{scanError}</Alert>}
          {secrets.length > 0 ? (
            <TableContainer component={Paper}>
              <Table size="small">
                <TableHead>
                  <TableRow>
                    <TableCell>File</TableCell>
                    <TableCell>Secret Type</TableCell>
                    <TableCell>Masked Snippet</TableCell>
                  </TableRow>
                </TableHead>
                <TableBody>
                  {secrets.map((secret, index) => (
                    <TableRow key={index}>
                      <TableCell>
                        <Link href={secret.url} target="_blank" rel="noopener">
                          {secret.file}
                        </Link>
                      </TableCell>
                      <TableCell>{secret.type}</TableCell>
                      <TableCell><code>{secret.snippet}</code></TableCell>
                    </TableRow>
                  ))}
                </TableBody>
              </Table>
            </TableContainer>
          ) : (
            <Typography sx={{ mt: 2 }}>No secrets found in scanned files.</Typography>
          )}
        </Box>
      )}
    </Paper>
  );
};

export default SecretDetection;