import React from 'react';
import { Box, Typography, CircularProgress } from '@mui/material';

interface HealthScoreCircleProps {
  score: number;
}

const HealthScoreCircle: React.FC<HealthScoreCircleProps> = ({ score }) => {
  const normalizedScore = Math.max(0, Math.min(100, score)); // Ensure score is between 0 and 100
  const progressColor = normalizedScore > 80 ? 'success' : normalizedScore > 60 ? 'warning' : 'error';

  return (
    <Box sx={{ position: 'relative', display: 'inline-flex', width: 100, height: 100 }}>
      <CircularProgress
        variant="determinate"
        value={normalizedScore}
        size={100}
        thickness={5}
        color={progressColor}
        sx={{
          position: 'absolute',
          left: 0,
          top: 0,
        }}
      />
      <Box
        sx={{
          top: 0,
          left: 0,
          bottom: 0,
          right: 0,
          position: 'absolute',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          flexDirection: 'column',
        }}
      >
        <Typography variant="h5" component="div" color="text.primary" sx={{ fontWeight: 600 }}>
          {`${Math.round(normalizedScore)}`}
        </Typography>
        <Typography variant="caption" component="div" color="text.secondary">
          / 100
        </Typography>
      </Box>
    </Box>
  );
};

export default HealthScoreCircle;
