import React from 'react';
import { Paper, Typography, Box, Avatar } from '@mui/material';

interface TechStackDisplayProps {
  technologies: { name: string; icon: string }[];
}

const TechStackDisplay: React.FC<TechStackDisplayProps> = ({ technologies }) => {
  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Tech Stack</Typography>
      <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
        {technologies.map((tech) => (
          <Box key={tech.name} sx={{ textAlign: 'center' }}>
            <Avatar src={tech.icon} alt={tech.name} sx={{ width: 48, height: 48, mx: 'auto', mb: 0.5 }} />
            <Typography variant="caption">{tech.name}</Typography>
          </Box>
        ))}
      </Box>
    </Paper>
  );
};

export default TechStackDisplay;
