import React, { useEffect, useState } from 'react';
import { useParams } from 'react-router-dom';
import { Container, Typography, Box, Paper, CircularProgress, Alert, Grid, Chip, Tabs, Tab } from '@mui/material';
import { getRepository } from '../services/api';
import { GitHubRepo } from '../types/github';
import StarIcon from '@mui/icons-material/Star';
import ForkRightIcon from '@mui/icons-material/ForkRight';
import HealthScoreCircle from '../components/HealthScoreCircle';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import SecretDetection from '../components/analysis/SecretDetection';

// Overview Tab Components
import TechStackDisplay from '../components/TechStackDisplay';
import ContributorSummary from '../components/ContributorSummary';
import ActivityTimelineChart from '../components/ActivityTimelineChart';

// Right Panel Components
import QuickIntelligencePanel from '../components/QuickIntelligencePanel'; // Import QuickIntelligencePanel

interface TabPanelProps {
  children?: React.ReactNode;
  index: number;
  value: number;
}

function TabPanel(props: TabPanelProps) {
  const { children, value, index, ...other } = props;

  return (
    <div
      role="tabpanel"
      hidden={value !== index}
      id={`simple-tabpanel-${index}`}
      aria-labelledby={`simple-tab-${index}`}
      {...other}
    >
      {value === index && (
        <Box sx={{ p: 3 }}>
          {children}
        </Box>
      )}
    </div>
  );
}

function a11yProps(index: number) {
  return {
    id: `simple-tab-${index}`,
    'aria-controls': `simple-tabpanel-${index}`,
  };
}

const RepositoryPage: React.FC = () => {
  const { owner, repoName } = useParams<{ owner: string; repoName: string }>();
  const [repo, setRepo] = useState<GitHubRepo | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [tabValue, setTabValue] = useState(0);

  const handleTabChange = (event: React.SyntheticEvent, newValue: number) => {
    setTabValue(newValue);
  };

  useEffect(() => {
    const fetchRepo = async () => {
      if (!owner || !repoName) return;
      setLoading(true);
      try {
        const data = await getRepository(owner, repoName);
        setRepo(data);
      } catch (err: any) {
        setError(err.message || 'An error occurred');
      } finally {
        setLoading(false);
      }
    };
    fetchRepo();
  }, [owner, repoName]);

  if (loading) {
    return <CircularProgress />;
  }

  if (error) {
    return <Alert severity="error">{error}</Alert>;
  }

  if (!repo) {
    return <Alert severity="info">Repository not found.</Alert>;
  }

  // Placeholder for health score, will be dynamic later
  const healthScore = 92;

  // Placeholder data for Tech Stack and Contributors
  const technologies = [
    { name: 'Python', icon: 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/python/python-original.svg' },
    { name: 'Starlette', icon: 'https://www.starlette.io/img/starlette.png' },
    { name: 'Pydantic', icon: 'https://pydantic-docs.helpmanual.io/img/logo.svg' },
    { name: 'Uvicorn', icon: 'https://www.uvicorn.org/img/uvicorn.png' },
    { name: 'Docker', icon: 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/docker/docker-original.svg' },
    { name: 'Kubernetes', icon: 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/kubernetes/kubernetes-original.svg' },
    { name: 'PostgreSQL', icon: 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/postgresql/postgresql-original.svg' },
    { name: 'Redis', icon: 'https://cdn.jsdelivr.net/gh/devicons/devicon/icons/redis/redis-original.svg' },
  ];

  const contributors = [
    { login: 'tiangolo', avatar_url: 'https://avatars.githubusercontent.com/u/1000000?v=4' }, // Placeholder
    { login: 'Kludex', avatar_url: 'https://avatars.githubusercontent.com/u/1000001?v=4' }, // Placeholder
    { login: 'dmontagu', avatar_url: 'https://avatars.githubusercontent.com/u/1000002?v=4' }, // Placeholder
    { login: 'dependabot[bot]', avatar_url: 'https://avatars.githubusercontent.com/u/49699333?s=200&v=4' }, // Placeholder
    { login: 'lauriolou', avatar_url: 'https://avatars.githubusercontent.com/u/1000003?v=4' }, // Placeholder
  ];


  return (
    <Container maxWidth="lg" sx={{ mt: 4 }}>
      <Grid container spacing={3}>
        {/* Main Content Area */}
        <Grid item xs={12} md={9}>
          <Paper sx={{ p: 3 }}>
            <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', mb: 2 }}>
              <Box>
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <Typography variant="h4" component="h1" sx={{ fontWeight: 600, mr: 1 }}>
                    {repo.owner.login} / {repo.name}
                  </Typography>
                  <CheckCircleIcon color="success" /> {/* Checkmark icon */}
                </Box>
                <Typography variant="subtitle1" color="text.secondary">
                  {repo.owner.login}
                </Typography>
                <Typography variant="body1" color="text.secondary" sx={{ mt: 1 }}>
                  {repo.description}
                </Typography>
                <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2, mt: 2 }}>
                    <Chip icon={<StarIcon />} label={`${repo.stargazers_count} Stars`} />
                    <Chip icon={<ForkRightIcon />} label={`${repo.forks_count} Forks`} />
                    {repo.license && <Chip label={`License: ${repo.license.name}`} variant="outlined" />}
                </Box>
              </Box>
              <Box sx={{ textAlign: 'center' }}>
                <HealthScoreCircle score={healthScore} />
                <Typography variant="caption" color="text.secondary" sx={{ mt: 1 }}>
                  Health Score
                </Typography>
              </Box>
            </Box>

            <Box sx={{ borderBottom: 1, borderColor: 'divider', mt: 3 }}>
              <Tabs value={tabValue} onChange={handleTabChange} aria-label="repository tabs">
                <Tab label="Overview" {...a11yProps(0)} />
                <Tab label="Security Findings" {...a11yProps(1)} />
                <Tab label="Secret Detection" {...a11yProps(2)} />
                <Tab label="Code Insights" {...a11yProps(3)} />
                <Tab label="Contributor Network" {...a11yProps(4)} />
              </Tabs>
            </Box>

            <TabPanel value={tabValue} index={0}>
              <Grid container spacing={3}>
                <Grid item xs={12}>
                  <Typography variant="h6" gutterBottom>Summary</Typography>
                  <Typography variant="body2">
                    {repo.description || "No summary available."}
                  </Typography>
                </Grid>
                <Grid item xs={12} md={6}>
                  <TechStackDisplay technologies={technologies} />
                </Grid>
                <Grid item xs={12} md={6}>
                  <ContributorSummary contributors={contributors} totalContributors={repo.forks_count + repo.stargazers_count} />
                </Grid>
                <Grid item xs={12}>
                  <ActivityTimelineChart />
                </Grid>
              </Grid>
            </TabPanel>
            <TabPanel value={tabValue} index={1}>
              {/* Security Findings Tab Content */}
              <Typography>Security Findings content</Typography>
            </TabPanel>
            <TabPanel value={tabValue} index={2}>
              {/* Secret Detection Tab Content */}
              <SecretDetection owner={owner!} repoName={repoName!} defaultBranch={repo.default_branch} />
            </TabPanel>
            <TabPanel value={tabValue} index={3}>
              {/* Code Insights Tab Content */}
              <Typography>Code Insights content</Typography>
            </TabPanel>
            <TabPanel value={tabValue} index={4}>
              {/* Contributor Network Tab Content */}
              <Typography>Contributor Network content</Typography>
            </TabPanel>
          </Paper>
        </Grid>

        {/* Right Panel */}
        <Grid item xs={12} md={3}>
          <QuickIntelligencePanel />
        </Grid>
      </Grid>
    </Container>
  );
};

export default RepositoryPage;

