import axios from 'axios';
import { GitHubSearchResult, GitHubRepo, GitHubCommit, GitHubContributor, GitHubTreeItem, GitHubTreeResponse } from '../types/github';

const GITHUB_API_URL = 'https://api.github.com';

const getAuthToken = (): string | undefined => {
  return process.env.REACT_APP_GITHUB_PAT;
};

const api = axios.create({
  baseURL: GITHUB_API_URL,
});

api.interceptors.request.use(config => {
  const token = getAuthToken();
  if (token) {
    config.headers.Authorization = `Bearer ${token}`;
  }
  return config;
});

export const searchRepositories = async (query: string): Promise<GitHubSearchResult> => {
  const response = await api.get(`/search/repositories?q=${query}`);
  return response.data;
};

export const getRepository = async (owner: string, repo: string): Promise<GitHubRepo> => {
  const response = await api.get(`/repos/${owner}/${repo}`);
  return response.data;
};

// Add more functions for other analyses, e.g., get repository content
export const getRepositoryContent = async (owner: string, repo: string, path: string = '') => {
  const response = await api.get(`/repos/${owner}/${repo}/contents/${path}`);
  return response.data;
};

export const getRepoLanguages = async (owner: string, repo: string): Promise<Record<string, number>> => {
  const response = await api.get(`/repos/${owner}/${repo}/languages`);
  return response.data;
};

export const getRepoCommits = async (owner: string, repo: string, per_page: number = 30): Promise<GitHubCommit[]> => {
  const response = await api.get(`/repos/${owner}/${repo}/commits?per_page=${per_page}`);
  return response.data;
};

export const getRepoContributors = async (owner: string, repo: string, per_page: number = 30): Promise<GitHubContributor[]> => {
  const response = await api.get(`/repos/${owner}/${repo}/contributors?per_page=${per_page}`);
  return response.data;
};

export const getRepoTree = async (owner: string, repo: string, sha: string = 'HEAD', recursive: boolean = true): Promise<GitHubTreeResponse> => {
  const recursiveParam = recursive ? '?recursive=1' : '';
  const response = await api.get(`/repos/${owner}/${repo}/git/trees/${sha}${recursiveParam}`);
  return response.data;
};
