import React from 'react';
import { Paper, Typography, Box } from '@mui/material';
import ArrowUpwardIcon from '@mui/icons-material/ArrowUpward';
import ArrowDownwardIcon from '@mui/icons-material/ArrowDownward';

interface MetricCardProps {
  title: string;
  value: string;
  change?: number; // Percentage change, e.g., 2.5 for 2.5%
  changeType?: 'positive' | 'negative' | 'neutral';
}

const MetricCard: React.FC<MetricCardProps> = ({ title, value, change, changeType = 'neutral' }) => {
  const changeColor = changeType === 'positive' ? 'success.main' : changeType === 'negative' ? 'error.main' : 'text.secondary';
  const ChangeIcon = changeType === 'positive' ? ArrowUpwardIcon : changeType === 'negative' ? ArrowDownwardIcon : null;

  return (
    <Paper sx={{ p: 2, display: 'flex', flexDirection: 'column', justifyContent: 'space-between', height: '100%' }}>
      <Typography variant="subtitle2" color="text.secondary" gutterBottom>
        {title}
      </Typography>
      <Typography variant="h5" component="div" sx={{ fontWeight: 600 }}>
        {value}
      </Typography>
      {change !== undefined && (
        <Box sx={{ display: 'flex', alignItems: 'center', mt: 1 }}>
          {ChangeIcon && <ChangeIcon sx={{ color: changeColor, fontSize: 16, mr: 0.5 }} />}
          <Typography variant="body2" sx={{ color: changeColor }}>
            {change > 0 ? '+' : ''}{change}% this week
          </Typography>
        </Box>
      )}
    </Paper>
  );
};

export default MetricCard;
