import React from 'react';
import { Paper, Typography, Box, List, ListItem, ListItemText, ListItemIcon, LinearProgress } from '@mui/material';
import GitHubIcon from '@mui/icons-material/GitHub';
import FavoriteIcon from '@mui/icons-material/Favorite'; // Placeholder for health icon

interface TrendingRepo {
  name: string;
  owner: string;
  healthScore: number;
  stars: string;
}

const trendingRepos: TrendingRepo[] = [
  { name: 'openai/gpt-4-turbo', owner: 'openai', healthScore: 98, stars: '45K' },
  { name: 'vercel/next.js', owner: 'vercel', healthScore: 88, stars: '110K' },
  { name: 'pytorch/pytorch', owner: 'pytorch', healthScore: 97, stars: '70K' },
  { name: 'facebook/react', owner: 'facebook', healthScore: 99, stars: '210K' },
];

const TrendingRepositories: React.FC = () => {
  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Trending Repositories</Typography>
      <List>
        {trendingRepos.map((repo, index) => (
          <ListItem key={index} disablePadding sx={{ mb: 1 }}>
            <ListItemIcon>
              <GitHubIcon />
            </ListItemIcon>
            <ListItemText
              primary={
                <Typography variant="body1" sx={{ fontWeight: 500 }}>
                  {repo.owner}/{repo.name}
                </Typography>
              }
              secondary={
                <Box sx={{ display: 'flex', alignItems: 'center' }}>
                  <FavoriteIcon sx={{ fontSize: 16, color: 'error.main', mr: 0.5 }} />
                  <Typography variant="body2" color="text.secondary" sx={{ mr: 1 }}>
                    {repo.stars}
                  </Typography>
                  <Typography variant="body2" color="text.secondary" sx={{ mr: 0.5 }}>
                    Health:
                  </Typography>
                  <LinearProgress
                    variant="determinate"
                    value={repo.healthScore}
                    sx={{ width: 50, height: 8, borderRadius: 5, mr: 0.5 }}
                    color={repo.healthScore > 90 ? 'success' : repo.healthScore > 70 ? 'warning' : 'error'}
                  />
                  <Typography variant="body2" color="text.secondary">
                    {repo.healthScore}%
                  </Typography>
                </Box>
              }
            />
          </ListItem>
        ))}
      </List>
    </Paper>
  );
};

export default TrendingRepositories;
