import React from 'react';
import { Paper, Typography, Box, Avatar, Tooltip } from '@mui/material';

interface Contributor {
  login: string;
  avatar_url: string;
}

interface ContributorSummaryProps {
  contributors: Contributor[];
  totalContributors: number;
}

const ContributorSummary: React.FC<ContributorSummaryProps> = ({ contributors, totalContributors }) => {
  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Contributor Summary</Typography>
      <Box sx={{ display: 'flex', alignItems: 'center', flexWrap: 'wrap', gap: 1 }}>
        {contributors.slice(0, 5).map((contributor) => ( // Show top 5
          <Tooltip key={contributor.login} title={contributor.login}>
            <Avatar src={contributor.avatar_url} alt={contributor.login} />
          </Tooltip>
        ))}
        {totalContributors > 5 && (
          <Typography variant="body2" color="text.secondary">
            Top 5 Contributors, Total {totalContributors}+
          </Typography>
        )}
      </Box>
    </Paper>
  );
};

export default ContributorSummary;
