import React from 'react';
import { Paper, Typography, Box, List, ListItem, ListItemText, ListItemIcon, LinearProgress } from '@mui/material';
import SecurityIcon from '@mui/icons-material/Security';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import WarningIcon from '@mui/icons-material/Warning';

interface ScoreCardProps {
  title: string;
  score: number; // 0-100
  description: string;
  color: 'success' | 'warning' | 'error';
}

const ScoreCard: React.FC<ScoreCardProps> = ({ title, score, description, color }) => {
  return (
    <Box sx={{ mb: 2 }}>
      <Typography variant="subtitle2" color="text.secondary">{title}</Typography>
      <Box sx={{ display: 'flex', alignItems: 'center', mt: 0.5 }}>
        <LinearProgress
          variant="determinate"
          value={score}
          color={color}
          sx={{ flexGrow: 1, height: 8, borderRadius: 5, mr: 1 }}
        />
        <Typography variant="body2" color="text.primary">{score}/100</Typography>
      </Box>
      <Typography variant="caption" color="text.secondary">{description}</Typography>
    </Box>
  );
};

interface SecurityEvent {
  id: number;
  type: 'new_release' | 'dependency_update' | 'potential_secrets' | 'vulnerability_scan';
  description: string;
  time: string;
}

const recentSecurityEvents: SecurityEvent[] = [
  { id: 1, type: 'new_release', description: 'New release: 0.109.2 (Security Fix)', time: '2 days ago' },
  { id: 2, type: 'dependency_update', description: 'Dependency update: Starlette to 0.35.0', time: '5 days ago' },
  { id: 3, type: 'potential_secrets', description: 'Potential secrets scanned and cleared', time: '1 week ago' },
  { id: 4, type: 'vulnerability_scan', description: 'Vulnerability Scan: No Critical issues found', time: '2 Weeks ago' },
];

const getEventIcon = (type: SecurityEvent['type']) => {
  switch (type) {
    case 'new_release': return <CheckCircleIcon color="success" fontSize="small" />;
    case 'dependency_update': return <WarningIcon color="warning" fontSize="small" />;
    case 'potential_secrets': return <SecurityIcon color="error" fontSize="small" />;
    case 'vulnerability_scan': return <CheckCircleIcon color="success" fontSize="small" />;
    default: return <SecurityIcon color="info" fontSize="small" />;
  }
};

const QuickIntelligencePanel: React.FC = () => {
  return (
    <Paper sx={{ p: 2, height: '100%' }}>
      <Typography variant="h6" gutterBottom>Quick Intelligence Panel</Typography>

      <ScoreCard title="Risk Score" score={8} description="Low - 8/100" color="error" />
      <ScoreCard title="Security Score" score={95} description="High - 95/100" color="success" />
      <ScoreCard title="Activity Score" score={98} description="Very High - 98/100" color="success" />
      <ScoreCard title="Maintenance Score" score={90} description="Active - 90/100" color="success" />

      <Typography variant="h6" gutterBottom sx={{ mt: 3 }}>Recent Security Events</Typography>
      <List dense>
        {recentSecurityEvents.map((event) => (
          <ListItem key={event.id} disablePadding sx={{ mb: 0.5 }}>
            <ListItemIcon sx={{ minWidth: 35 }}>
              {getEventIcon(event.type)}
            </ListItemIcon>
            <ListItemText
              primary={<Typography variant="body2">{event.description}</Typography>}
              secondary={<Typography variant="caption" color="text.secondary">{event.time}</Typography>}
            />
          </ListItem>
        ))}
      </List>
    </Paper>
  );
};

export default QuickIntelligencePanel;
