import React from 'react';
import { List, ListItem, ListItemText, Paper, Typography, Box, Chip } from '@mui/material';
import { Link as RouterLink } from 'react-router-dom';
import { GitHubRepo } from '../types/github';
import StarIcon from '@mui/icons-material/Star';
import ForkRightIcon from '@mui/icons-material/ForkRight';

interface SearchResultsProps {
  repositories: GitHubRepo[];
}

const SearchResults: React.FC<SearchResultsProps> = ({ repositories }) => {
  if (repositories.length === 0) {
    return <Typography sx={{ textAlign: 'center', mt: 4 }}>No repositories found. Try a new search.</Typography>;
  }

  return (
    <Paper>
      <List>
        {repositories.map((repo) => (
          <ListItem 
            key={repo.id} 
            divider 
            button 
            component={RouterLink} 
            to={`/repo/${repo.owner.login}/${repo.name}`}
          >
            <ListItemText
              primary={repo.full_name}
              secondary={
                <>
                  <Typography component="span" variant="body2" color="text.primary">
                    {repo.description}
                  </Typography>
                  <Box sx={{ mt: 1, display: 'flex', alignItems: 'center' }}>
                    <Chip icon={<StarIcon />} label={repo.stargazers_count} size="small" sx={{ mr: 1 }} />
                    <Chip icon={<ForkRightIcon />} label={repo.forks_count} size="small" sx={{ mr: 1 }} />
                    {repo.license && <Chip label={repo.license.name} size="small" variant="outlined" />}
                  </Box>
                </>
              }
            />
          </ListItem>
        ))}
      </List>
    </Paper>
  );
};

export default SearchResults;
